#include<bits/stdc++.h>
using namespace std;
int n,q,tot;
int z[200010],v[200010],a[200010];
long long m,sum[200010];
int solve(int x)
{
    int l=1,r=tot,best=tot;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(z[mid]>x)
        {
            r=mid-1;
            best=r;
        }
        else
        {
            l=mid+1;
        }
    }
    return best;
}
int main()
{
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    int j=-1;
    for(int i=n;i>=1;i--)
    {
        if(a[i]>0)
        {
            j=i;
            m=0;
            z[++tot]=i;
        }
        m+=a[i];
        if(m>0)
        {
            v[j]++;
        }
    }
    sort(z+1,z+1+tot);
    for(int i=1;i<=tot;i++)
    {
        sum[i]=sum[i-1]+v[z[i]];
    }
    while(q--)
    {
        int l,r;
        scanf("%d%d",&l,&r);
        int a=solve(l),b=solve(r);
        if(z[b]<l)
        {
            printf("0\n");
            continue;
        }
        if(z[a]<l)
        {
            a++;
        }
        printf("%lld\n",sum[b]-sum[a]+min(v[z[a]],z[a]-l+1));
    }
    return 0;
}
